#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum CallReturnKind {
    Call,
    CallWithThis,
}

impl CallReturnKind {
    pub(crate) const fn opcode(self) -> CoreOpcode {
        match self {
            Self::Call => CoreOpcode::Call,
            Self::CallWithThis => CoreOpcode::CallWithThis,
        }
    }

    pub(crate) const fn from_opcode(opcode: CoreOpcode) -> Option<Self> {
        match opcode {
            CoreOpcode::Call => Some(Self::Call),
            CoreOpcode::CallWithThis => Some(Self::CallWithThis),
            _ => None,
        }
    }
}

