#[derive(Clone, Debug, Eq, PartialEq)]
pub struct FunctionValuePropertyObservation {
    kind: FunctionValuePropertyObservationKind,
}

impl FunctionValuePropertyObservation {
    pub(crate) fn none() -> Self {
        Self {
            kind: FunctionValuePropertyObservationKind::None,
        }
    }

    fn property_load(record: CorePropertyLookupRecord) -> Self {
        Self {
            kind: FunctionValuePropertyObservationKind::PropertyLoad { record },
        }
    }

    fn property_has(record: CorePropertyLookupRecord) -> Self {
        Self {
            kind: FunctionValuePropertyObservationKind::PropertyHas { record },
        }
    }

    fn property_store(
        site: CorePropertyStoreSite,
        object: RuntimeValue,
        key: CorePropertyKey,
        stored_value: RuntimeValue,
        before: CorePropertyStoreSnapshot,
        barrier_start: usize,
        returned_outcome: PropertyStoreObservationOutcome,
    ) -> Self {
        Self {
            kind: FunctionValuePropertyObservationKind::PropertyStore {
                site,
                object,
                key,
                stored_value,
                before,
                barrier_start,
                returned_outcome,
            },
        }
    }
}

