pub enum CallObservationRootSafety {
    RootSafe,
    Blocked,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum CallObservationDirectCallReadiness {
    Disallowed,
    Allowed,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct CallObservationDescriptor {
    pub owner: CodeBlockId,
    pub frame: CallFrameId,
    pub bytecode_index: u32,
    pub opcode: CoreOpcode,
    pub destination: VirtualRegister,
    pub callee_register: VirtualRegister,
    pub callee_value_kind: ValueKind,
    pub callee_object: Option<ObjectId>,
    pub this_source: CallObservationThisSource,
    pub this_value_kind: ValueKind,
    pub this_object: Option<ObjectId>,
    pub provided_argument_count: u32,
    pub argument_count_including_this: u32,
    pub target_kind: CallObservationTargetKind,
    pub target_executable: Option<ExecutableId>,
    pub target_code_block: Option<CodeBlockId>,
    pub outcome: CallObservationOutcome,
    pub may_call_js: bool,
    pub root_safety: CallObservationRootSafety,
    pub direct_call_readiness: CallObservationDirectCallReadiness,
}

impl CallObservationDescriptor {
    pub fn validate(&self) -> Result<(), ExecutionError> {
        if !matches!(
            self.opcode,
            CoreOpcode::Call | CoreOpcode::CallWithThis | CoreOpcode::Construct
        ) {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        match (self.opcode, self.this_source) {
            (CoreOpcode::Call, CallObservationThisSource::ImplicitUndefined)
                if self.this_object.is_none() => {}
            (CoreOpcode::CallWithThis, CallObservationThisSource::ExplicitRegister(_)) => {}
            (CoreOpcode::Construct, CallObservationThisSource::ConstructAllocatedReceiver) => {}
            _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
        if self.argument_count_including_this
            != self
                .provided_argument_count
                .checked_add(1)
                .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.direct_call_readiness != CallObservationDirectCallReadiness::Disallowed {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.root_safety == CallObservationRootSafety::RootSafe
            && self.callee_value_kind == ValueKind::Cell
            && self.callee_object.is_none()
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.root_safety == CallObservationRootSafety::RootSafe
            && self.opcode == CoreOpcode::CallWithThis
            && self.this_value_kind == ValueKind::Cell
            && self.this_object.is_none()
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.root_safety == CallObservationRootSafety::RootSafe
            && self.opcode == CoreOpcode::Construct
            && self.this_value_kind == ValueKind::Cell
            && self.this_object.is_none()
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.root_safety == CallObservationRootSafety::Blocked
            && (!matches!(self.target_kind, CallObservationTargetKind::Opaque) || !self.may_call_js)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        match self.target_kind {
            CallObservationTargetKind::BytecodeFunction { .. } => {
                if self.target_executable.is_none() != self.target_code_block.is_none() {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            _ => {
                if self.target_executable.is_some() || self.target_code_block.is_some() {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
        }
        Ok(())
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum PropertyStoreObservationOutcome {
    OwnDataStore,
    CreatedProperty,
    IndexedStore,
    Setter,
    Proxy,
    Ignored,
    Opaque,
    Throw,
    Error,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct PropertyStoreObservationDescriptor {
    pub owner: CodeBlockId,
    pub frame: CallFrameId,
    pub slot: InlineCacheSlotId,
    pub bytecode_index: u32,
    pub cache_kind: InlineCacheKind,
    pub fallback: InlineCacheFallbackSemantics,
    pub key: CacheKey,
    pub base_object: Option<ObjectId>,
    pub base_structure_before: Option<StructureId>,
    pub base_structure_after: Option<StructureId>,
    pub offset_after: Option<PropertyOffset>,
    pub stored_value: RuntimeValue,
    pub outcome: PropertyStoreObservationOutcome,
    pub may_call_js: bool,
    pub cacheability: PropertyCacheability,
    pub can_use_put_by_id_megamorphic: bool,
    pub write_barrier_count: u32,
    pub last_write_barrier: Option<BarrierRequirementOutcome>,
    pub cold_miss_handoff: InlineCacheMissHandoffDescriptor,
}

impl PropertyStoreObservationDescriptor {
    pub fn validate(&self) -> Result<(), ExecutionError> {
        if !matches!(
            self.cache_kind,
            InlineCacheKind::PropertyStore | InlineCacheKind::ElementStore
        ) {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.fallback != InlineCacheFallbackSemantics::SlowPathLookup {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.cacheability == PropertyCacheability::Allowed {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self.cold_miss_handoff.owner != self.owner
            || self.cold_miss_handoff.slot != self.slot
            || self.cold_miss_handoff.bytecode_index != self.bytecode_index
            || self.cold_miss_handoff.cache_kind != self.cache_kind
            || self.cold_miss_handoff.fallback != self.fallback
            || self.cold_miss_handoff.miss_kind != crate::jit::InlineCacheMissKind::Cold
            || self.cold_miss_handoff.boundary.is_some()
            || self.cold_miss_handoff.call_link.is_some()
            || !self.cold_miss_handoff.preserves_operand_registers
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        Ok(())
    }
}

