pub trait DispatchHost {
    fn targeted_register_roots(
        &mut self,
        _heap: &mut Heap,
        _snapshot: &ExecutionRootSnapshot,
    ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
        Ok(Vec::new())
    }

    /// Fill `out` (cleared first) with the same targeted register-root records
    /// `targeted_register_roots` would return, reusing the caller-owned buffer
    /// instead of allocating a fresh Vec per call. The default delegates to
    /// `targeted_register_roots` (still one allocation) so test/non-production
    /// hosts need no change; the production `CoreOpcodeDispatchHost` overrides it
    /// to fill `out` directly. Used by the per-instruction dispatch-loop root
    /// sync where the allocation dominated the hot loop.
    fn targeted_register_roots_into(
        &mut self,
        heap: &mut Heap,
        snapshot: &ExecutionRootSnapshot,
        out: &mut Vec<TargetedRootRecord>,
    ) -> Result<(), ExecutionError> {
        let records = self.targeted_register_roots(heap, snapshot)?;
        out.clear();
        out.extend(records);
        Ok(())
    }

    fn drain_property_load_observation(
        &mut self,
        _heap: &mut Heap,
        _request: PropertyLoadObservationDrainRequest,
    ) -> Result<Option<PropertyLoadObservationDescriptor>, ExecutionError> {
        Ok(None)
    }

    fn drain_property_store_observation(
        &mut self,
        _heap: &mut Heap,
        _request: PropertyStoreObservationDrainRequest,
    ) -> Result<Option<PropertyStoreObservationDescriptor>, ExecutionError> {
        Ok(None)
    }

    fn discard_property_store_observations(&mut self) {}

    fn drain_property_has_observation(
        &mut self,
        _heap: &mut Heap,
        _request: PropertyHasObservationDrainRequest,
    ) -> Result<Option<PropertyHasObservationDescriptor>, ExecutionError> {
        Ok(None)
    }

    fn drain_call_observation(
        &mut self,
        _heap: &mut Heap,
        _request: CallObservationDrainRequest,
    ) -> Result<Option<CallObservationDescriptor>, ExecutionError> {
        Ok(None)
    }

    fn finalize_function_value_property_observation(
        &mut self,
        _heap: &mut Heap,
        _observation: FunctionValuePropertyObservation,
        _outcome: FunctionValuePropertyOperationOutcome,
    ) -> Result<(), ExecutionError> {
        Ok(())
    }

    fn function_value_property_return_truthy(&mut self, value: RuntimeValue) -> bool {
        value.pure_to_boolean()
    }

    fn normalize_constructor_return(
        &mut self,
        returned: RuntimeValue,
        constructor_this: RuntimeValue,
    ) -> RuntimeValue {
        if returned.as_cell().is_some() {
            returned
        } else {
            constructor_this
        }
    }

    fn initialize_construct_return_fields(
        &mut self,
        _state: &mut DispatchState<'_>,
        constructors: &[RuntimeValue],
        _receiver: RuntimeValue,
    ) -> Result<(), DispatchOutcome> {
        if constructors.is_empty() {
            Ok(())
        } else {
            Err(DispatchOutcome::Fail(ExecutionError::ExpectedFunction))
        }
    }

    // --- Indirect-eval host hooks (C++ JSC globalFuncEval -> executeEval) ---
    //
    // The Vm owns the eval compile pipeline but the function-block table, source
    // string/identifier maps, and global lexical environment live on the host
    // (`CoreOpcodeDispatchHost`). These hooks let the Vm eval handler read the
    // current function-block base (so newly compiled eval functions are indexed
    // contiguously, matching `append_source_session_source`), append the eval's
    // compiled function blocks/strings/identifiers, and install the eval body's
    // top-level lexical (`let`/`const`) declarations as global lexical bindings.
    // Defaults make eval unavailable on non-production hosts (test hosts), which
    // never compile source. Only `CoreOpcodeDispatchHost` overrides them.
    fn eval_function_block_base(&self) -> Option<u32> {
        None
    }

    fn eval_global_binding_set(&self) -> Option<BytecompilerGlobalBindingSet> {
        None
    }

    // Snapshot of the host's current identifier/string-literal namespace so the
    // Vm-owned eval compile reuses existing identifier indices and allocates
    // fresh, non-colliding indices for new names. Eval bytecode resolves
    // identifier indices through the host's shared `identifier_texts` map, so a
    // from-zero compile would corrupt resolution; this seeds the eval compile's
    // stable-id allocator to continue the program's namespace.
    fn eval_symbol_namespace_snapshot(&self) -> EvalHostSymbolSnapshot {
        EvalHostSymbolSnapshot::default()
    }

    fn append_eval_function_blocks(
        &mut self,
        _function_blocks: Vec<InterpreterFunctionCodeBlock>,
        _string_literals: HashMap<u32, String>,
        _identifier_texts: HashMap<u32, String>,
        _prototype_property_key: Option<u32>,
    ) {
    }

    fn install_eval_global_lexical_declarations(
        &mut self,
        _declarations: Vec<CoreGlobalLexicalDeclaration>,
    ) -> Result<(), ExecutionError> {
        Ok(())
    }

    fn snapshot_structure_transition_watchpoints(
        &mut self,
        _requests: &[StructureTransitionWatchpointRequest],
    ) -> Result<Vec<StructureTransitionWatchpointSnapshot>, ExecutionError> {
        Ok(Vec::new())
    }

    fn start_structure_transition_watchpoints(
        &mut self,
        _requests: &[StructureTransitionWatchpointRequest],
    ) -> Result<Vec<StructureTransitionWatchpointSnapshot>, ExecutionError> {
        Ok(Vec::new())
    }

    fn drain_watchpoint_fire_events(&mut self) -> Vec<WatchpointFireEvent> {
        Vec::new()
    }

    fn has_pending_structure_chain_invalidation_events(&mut self) -> bool {
        false
    }

    fn drain_structure_chain_invalidation_events(
        &mut self,
    ) -> Vec<StructureChainInvalidationEvent> {
        Vec::new()
    }

    fn generated_property_sidecar_base_structure(
        &mut self,
        _base: RuntimeValue,
    ) -> Option<StructureId> {
        None
    }

    // Resolve a prototype-load HOLDER object id to the raw, pinned
    // `CoreObjectCell*` (as `usize` bits) that a resident prototype DataIC bakes
    // into its record (`offsetOfInlineHolder` analog,
    // jit/JITInlineCacheGenerator.cpp:158). The pointer is the never-moving
    // `Pin<Box<CoreObjectCell>>` address. Returns `None` when the holder is not a
    // live object the store knows, or is an opaque object (proxy) the resident
    // DataIC must not bake. The default (test/non-production hosts) resolves
    // nothing, so the prototype arm is a no-op and the site stays on the slow
    // path. Only the production `CoreOpcodeDispatchHost` overrides this.
    fn generated_prototype_holder_cell_pointer(&mut self, _holder: ObjectId) -> Option<u64> {
        None
    }

    fn generated_property_has_sidecar_base_structure(
        &mut self,
        _base: RuntimeValue,
    ) -> Option<StructureId> {
        None
    }

    fn generated_property_has_sidecar_runtime_key(
        &mut self,
        _property: RuntimeValue,
    ) -> Option<CacheKey> {
        None
    }

    fn probe_generated_property_load(
        &mut self,
        _request: GeneratedPropertyLoadProbeRequest<'_>,
    ) -> GeneratedPropertyLoadProbeResult {
        GeneratedPropertyLoadProbeResult::miss(
            GeneratedPropertyLoadProbeMissReason::HostUnavailable,
        )
    }

    fn probe_generated_property_load_megamorphic_holder(
        &mut self,
        _request: GeneratedPropertyLoadMegamorphicHolderProbeRequest,
    ) -> GeneratedPropertyLoadProbeResult {
        GeneratedPropertyLoadProbeResult::miss(
            GeneratedPropertyLoadProbeMissReason::HostUnavailable,
        )
    }

    fn probe_generated_property_store(
        &mut self,
        _request: GeneratedPropertyStoreProbeRequest<'_>,
    ) -> GeneratedPropertyStoreProbeResult {
        GeneratedPropertyStoreProbeResult::miss(
            GeneratedPropertyStoreProbeMissReason::HostUnavailable,
        )
    }

    fn commit_generated_property_store(
        &mut self,
        _heap: &mut Heap,
        _request: GeneratedPropertyStoreMutationRequest,
    ) -> GeneratedPropertyStoreMutationResult {
        GeneratedPropertyStoreMutationResult::rejected(
            GeneratedPropertyStoreMutationMissReason::HostUnavailable,
        )
    }

    fn probe_generated_guarded_property_load(
        &mut self,
        request: GeneratedGuardedPropertyLoadProbeRequest<'_>,
    ) -> GeneratedGuardedPropertyLoadProbeResult {
        GeneratedGuardedPropertyLoadProbeResult::miss_for_plan(
            GeneratedGuardedPropertyLoadProbeMissReason::HostUnavailable,
            request.plan,
            None,
        )
    }

    fn probe_generated_call_link(
        &mut self,
        _heap: &mut Heap,
        _request: GeneratedCallLinkProbeRequest<'_>,
    ) -> GeneratedCallLinkProbeResult {
        GeneratedCallLinkProbeResult::miss(GeneratedCallLinkProbeMissReason::HostUnavailable)
    }

    fn dispatch_generated_native_intrinsic_call(
        &mut self,
        _heap: &mut Heap,
        _request: GeneratedNativeIntrinsicCallRequest,
    ) -> GeneratedNativeIntrinsicCallResult {
        GeneratedNativeIntrinsicCallResult::miss(
            GeneratedNativeIntrinsicCallMissReason::HostUnavailable,
        )
    }

    fn dispatch_instruction(
        &mut self,
        state: &mut DispatchState<'_>,
        instruction: DispatchInstruction<'_>,
    ) -> DispatchOutcome;
}

