    fn type_error_value(
        &mut self,
        heap: &mut Heap,
        message: &str,
    ) -> Result<RuntimeValue, DispatchOutcome> {
        let error_name = self
            .strings
            .allocate_with_heap(heap, "Error")
            .map_err(DispatchOutcome::Fail)?;
        let type_error_name = self
            .strings
            .allocate_with_heap(heap, "TypeError")
            .map_err(DispatchOutcome::Fail)?;
        let empty_message = self
            .strings
            .allocate_with_heap(heap, "")
            .map_err(DispatchOutcome::Fail)?;
        let message = self
            .strings
            .allocate_with_heap(heap, message)
            .map_err(DispatchOutcome::Fail)?;
        let prototype =
            self.objects
                .ensure_type_error_prototype(error_name, type_error_name, empty_message);
        let error = self
            .objects
            .allocate_with_prototype_with_write_barrier(heap, Some(prototype))
            .map_err(DispatchOutcome::Fail)?;
        self.define_non_enumerable_data_field_with_write_barrier(heap, error, "message", message)?;
        Ok(error)
    }

    fn native_map_constructor(
        &mut self,
        heap: &mut Heap,
        arguments: &[RuntimeValue],
    ) -> Result<RuntimeValue, DispatchOutcome> {
        let map = self.objects.allocate_map();
        let Some(iterable) = arguments.first().copied() else {
            return Ok(map);
        };
        if iterable.kind() == ValueKind::Undefined {
            return Ok(map);
        }
        let entries = self.collect_iterable_values_to_array(
            heap,
            iterable,
            "Map initializer must be iterable",
        )?;
        let length =
            self.collection_initializer_length(heap, entries, "Map initializer must be iterable")?;
        for index in 0..length {
            let entry = self
                .objects
                .get_index(entries, index)
                .map_err(DispatchOutcome::Fail)?;
            if self.objects.array_length(entry).ok().flatten().is_none() {
                return Err(self
                    .type_error_outcome_with_heap(heap, "Map initializer entries must be arrays"));
            }
            let key = self
                .objects
                .get_index(entry, 0)
                .map_err(DispatchOutcome::Fail)?;
            let value = self
                .objects
                .get_index(entry, 1)
                .map_err(DispatchOutcome::Fail)?;
            self.map_set_entry(heap, map, key, value)?;
        }
        Ok(map)
    }

