pub(crate) fn execute_single_dispatch_deferring_ordinary_calls<H: DispatchHost>(
    execution: InterpreterExecutionState<'_>,
    request: SingleDispatchRequest,
    code_block: &CodeBlock,
    host: &mut H,
) -> SingleDispatchOutcome {
    execute_single_dispatch_with_ordinary_call_handling(
        execution,
        request,
        code_block,
        host,
        InterpreterCallHandling::defer_to_vm(),
    )
}

fn execute_single_dispatch_with_ordinary_call_handling<H: DispatchHost>(
    execution: InterpreterExecutionState<'_>,
    request: SingleDispatchRequest,
    code_block: &CodeBlock,
    host: &mut H,
    call_handling: InterpreterCallHandling,
) -> SingleDispatchOutcome {
    let cursor = InstructionCursor::new(code_block.unlinked().instructions());
    let frame = match validate_single_dispatch_request(execution.stack, cursor, request) {
        Ok(frame) => frame,
        Err(error) => return SingleDispatchOutcome::Failed(error),
    };
    let mut active_targeted_register_roots = Vec::new();
    let mut active_targeted_frame_roots = Vec::new();
    let mut register_root_scratch = RegisterRootSyncScratch::new();

    if let Err(error) = sync_targeted_frame_roots(
        frame.id,
        execution.stack,
        execution.registers,
        execution.heap,
        &mut active_targeted_frame_roots,
    ) {
        return finish_single_dispatch_with_targeted_root_cleanup(
            execution.heap,
            &mut active_targeted_register_roots,
            &mut active_targeted_frame_roots,
            SingleDispatchOutcome::Failed(error),
        );
    }

    if let Err(error) = sync_targeted_register_roots_buffered(
        frame.id,
        execution.stack,
        execution.registers,
        execution.heap,
        host,
        &mut active_targeted_register_roots,
        &mut register_root_scratch,
    ) {
        return finish_single_dispatch_with_targeted_root_cleanup(
            execution.heap,
            &mut active_targeted_register_roots,
            &mut active_targeted_frame_roots,
            SingleDispatchOutcome::Failed(error),
        );
    }

    let index = request.bytecode_index.offset() as usize;
    let view = match cursor.get(index) {
        Some(view) => view,
        None => {
            return finish_single_dispatch_with_targeted_root_cleanup(
                execution.heap,
                &mut active_targeted_register_roots,
                &mut active_targeted_frame_roots,
                SingleDispatchOutcome::Failed(ExecutionError::InvalidBytecodeIndex(
                    request.bytecode_index,
                )),
            );
        }
    };
    let bytecode_index = view.bytecode_index(index);
    execution.stack.mark_top_bytecode_index(bytecode_index);

    let instruction = DispatchInstruction {
        frame: frame.id,
        code_block: request.code_block,
        bytecode_index,
        next_bytecode_index: cursor
            .get(index.saturating_add(1))
            .map(|view| view.bytecode_index(index.saturating_add(1))),
        opcode: view.opcode(),
        operands: view.operands(),
    };
    let outcome = {
        let mut state = DispatchState {
            stack: &mut *execution.stack,
            registers: &mut *execution.registers,
            exceptions: &mut *execution.exceptions,
            heap: &mut *execution.heap,
            code_block,
            ordinary_bytecode_call_handling: call_handling.ordinary_bytecode_call,
            function_value_call_handling: call_handling.function_value_call,
        };
        host.dispatch_instruction(&mut state, instruction)
    };

    if let Err(error) = sync_targeted_register_roots_buffered(
        frame.id,
        execution.stack,
        execution.registers,
        execution.heap,
        host,
        &mut active_targeted_register_roots,
        &mut register_root_scratch,
    ) {
        return finish_single_dispatch_with_targeted_root_cleanup(
            execution.heap,
            &mut active_targeted_register_roots,
            &mut active_targeted_frame_roots,
            SingleDispatchOutcome::Failed(error),
        );
    }

    let outcome = map_single_dispatch_outcome(
        SingleDispatchOutcomeState {
            stack: &mut *execution.stack,
            registers: &mut *execution.registers,
            exceptions: &mut *execution.exceptions,
        },
        SingleDispatchOutcomeContext {
            frame: frame.id,
            code_block,
            cursor,
            index,
            bytecode_index,
            call_handling,
        },
        outcome,
    );
    finish_single_dispatch_with_targeted_root_cleanup(
        execution.heap,
        &mut active_targeted_register_roots,
        &mut active_targeted_frame_roots,
        outcome,
    )
}

struct SingleDispatchOutcomeState<'a> {
    stack: &'a mut ExecutionContextStack,
    registers: &'a mut RegisterFile,
    exceptions: &'a mut ExceptionState,
}

struct SingleDispatchOutcomeContext<'a> {
    frame: CallFrameId,
    code_block: &'a CodeBlock,
    cursor: InstructionCursor<'a>,
    index: usize,
    bytecode_index: BytecodeIndex,
    call_handling: InterpreterCallHandling,
}

fn execute_code_block_with_resume<H: DispatchHost>(
    execution: InterpreterExecutionState<'_>,
    code_block_id: CodeBlockId,
    code_block: &CodeBlock,
    host: &mut H,
    config: DispatchConfig,
    resume: Option<BaselineFallbackRequest>,
    call_handling: InterpreterCallHandling,
) -> ExecutionCompletion {
    let cursor = InstructionCursor::new(code_block.unlinked().instructions());
    let (frame, mut pc) = match resume {
        Some(request) => match validate_baseline_fallback_request(
            execution.stack,
            code_block_id,
            cursor,
            request,
        ) {
            Ok(frame) => (frame, request.bytecode_index),
            Err(error) => return ExecutionCompletion::Failed(error),
        },
        None => {
            if cursor.is_empty() {
                return ExecutionCompletion::Returned(RuntimeValue::undefined());
            }
            let Some(frame) = execution.stack.top_frame().cloned() else {
                return ExecutionCompletion::Failed(ExecutionError::NoActiveFrame);
            };
            let pc = frame
                .bytecode_index
                .unwrap_or_else(|| BytecodeIndex::from_offset(0));
            (frame, pc)
        }
    };
    let mut steps = 0usize;
    let mut active_targeted_register_roots = Vec::new();
    let mut active_targeted_frame_roots = Vec::new();
    // One scratch buffer set owned across all loop iterations so the
    // per-instruction register-root sync reuses its working collections instead
    // of allocating them every bytecode (see RegisterRootSyncScratch).
    let mut register_root_scratch = RegisterRootSyncScratch::new();

    if let Err(error) = sync_targeted_frame_roots(
        frame.id,
        execution.stack,
        execution.registers,
        execution.heap,
        &mut active_targeted_frame_roots,
    ) {
        return finish_with_targeted_root_cleanup(
            execution.heap,
            &mut active_targeted_register_roots,
            &mut active_targeted_frame_roots,
            ExecutionCompletion::Failed(error),
        );
    }

    // Pre-loop register-root sync stays UNCONDITIONAL: it establishes the
    // initial targeted-root state for this frame (a fresh entry or a baseline
    // re-entry resume, where generated code may have changed slot
    // cell-membership outside this loop's `write` funnel). Clear the dirty flag
    // immediately afterward so the first per-op gate sees a clean state.
    if let Err(error) = sync_targeted_register_roots_buffered(
        frame.id,
        execution.stack,
        execution.registers,
        execution.heap,
        host,
        &mut active_targeted_register_roots,
        &mut register_root_scratch,
    ) {
        return finish_with_targeted_root_cleanup(
            execution.heap,
            &mut active_targeted_register_roots,
            &mut active_targeted_frame_roots,
            ExecutionCompletion::Failed(error),
        );
    }
    execution.registers.clear_cell_root_dirty();

    loop {
        if let Some(reason) = execution.exceptions.termination() {
            return finish_with_targeted_root_cleanup(
                execution.heap,
                &mut active_targeted_register_roots,
                &mut active_targeted_frame_roots,
                ExecutionCompletion::Terminated(reason),
            );
        }
        if steps >= config.max_steps {
            return finish_with_targeted_root_cleanup(
                execution.heap,
                &mut active_targeted_register_roots,
                &mut active_targeted_frame_roots,
                ExecutionCompletion::Failed(ExecutionError::DispatchStepLimitExceeded),
            );
        }
        steps = steps.saturating_add(1);

        let index = pc.offset() as usize;
        let Some(view) = cursor.get(index) else {
            return finish_with_targeted_root_cleanup(
                execution.heap,
                &mut active_targeted_register_roots,
                &mut active_targeted_frame_roots,
                ExecutionCompletion::Failed(ExecutionError::InvalidBytecodeIndex(pc)),
            );
        };
        let bytecode_index = view.bytecode_index(index);
        execution.stack.mark_top_bytecode_index(bytecode_index);

        let instruction = DispatchInstruction {
            frame: frame.id,
            code_block: code_block_id,
            bytecode_index,
            next_bytecode_index: cursor
                .get(index.saturating_add(1))
                .map(|view| view.bytecode_index(index.saturating_add(1))),
            opcode: view.opcode(),
            operands: view.operands(),
        };
        let outcome = {
            let mut state = DispatchState {
                stack: &mut *execution.stack,
                registers: &mut *execution.registers,
                exceptions: &mut *execution.exceptions,
                heap: &mut *execution.heap,
                code_block,
                ordinary_bytecode_call_handling: call_handling.ordinary_bytecode_call,
                function_value_call_handling: call_handling.function_value_call,
            };
            host.dispatch_instruction(&mut state, instruction)
        };
        // C++ JSC divergence: C++ JSC does ZERO per-bytecode rooting -- the
        // LLInt dispatch macro only advances PC and jumps
        // (llint/LowLevelInterpreter.asm), and the JS register file is rooted
        // by one conservative span scan taken ONLY at a GC safepoint
        // (interpreter/CLoopStack.cpp gatherConservativeRoots,
        // heap/Heap.cpp gatherStackRoots), so rooting is O(stack) per GC, not
        // per op. Rust keeps a precise targeted VM-register root registry, but
        // recomputes it lazily: the per-op sync (a full window scan +
        // TargetedRootSet build/validate + register/retarget/unregister) runs
        // only when a write since the last reconcile may have changed a slot's
        // cell-membership (`RegisterFile::cell_root_dirty`). The dispatched op
        // is the only in-loop write source (`write_register` -> `write`), and
        // call/construct/return/unwind all EXIT this single-frame loop (the
        // `match outcome` below), so a clean flag here proves the root set is
        // still in the correct state -- identical to syncing unconditionally,
        // but a pure-arith / cell-stable hot loop pays nothing, approximating
        // the C++ safepoint model. Clear the flag only after a successful sync.
        if execution.registers.cell_root_dirty() {
            if let Err(error) = sync_targeted_register_roots_buffered(
                frame.id,
                execution.stack,
                execution.registers,
                execution.heap,
                host,
                &mut active_targeted_register_roots,
                &mut register_root_scratch,
            ) {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::Failed(error),
                );
            }
            execution.registers.clear_cell_root_dirty();
        }

        match outcome {
            DispatchOutcome::Continue => {
                let next = index.saturating_add(1);
                if next >= cursor.len() {
                    return finish_with_targeted_root_cleanup(
                        execution.heap,
                        &mut active_targeted_register_roots,
                        &mut active_targeted_frame_roots,
                        ExecutionCompletion::Returned(RuntimeValue::undefined()),
                    );
                }
                pc = BytecodeIndex::from_offset(next as u32);
            }
            DispatchOutcome::ContinueTo(target) => {
                let Some(target) = target else {
                    return finish_with_targeted_root_cleanup(
                        execution.heap,
                        &mut active_targeted_register_roots,
                        &mut active_targeted_frame_roots,
                        ExecutionCompletion::Returned(RuntimeValue::undefined()),
                    );
                };
                if cursor.get(target.offset() as usize).is_none() {
                    return finish_with_targeted_root_cleanup(
                        execution.heap,
                        &mut active_targeted_register_roots,
                        &mut active_targeted_frame_roots,
                        ExecutionCompletion::Failed(ExecutionError::InvalidBytecodeIndex(target)),
                    );
                }
                pc = target;
            }
            DispatchOutcome::Jump(target) => {
                if cursor.get(target.offset() as usize).is_none() {
                    return finish_with_targeted_root_cleanup(
                        execution.heap,
                        &mut active_targeted_register_roots,
                        &mut active_targeted_frame_roots,
                        ExecutionCompletion::Failed(ExecutionError::InvalidBytecodeIndex(target)),
                    );
                }
                pc = target;
            }
            DispatchOutcome::Return(value) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::Returned(value),
                );
            }
            DispatchOutcome::BaselineLoopHandoff(request) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::BaselineLoopHandoff(request),
                );
            }
            DispatchOutcome::OrdinaryBytecodeCall(request) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::OrdinaryBytecodeCall(request),
                );
            }
            DispatchOutcome::OrdinaryBytecodeConstruct(request) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::OrdinaryBytecodeConstruct(request),
                );
            }
            DispatchOutcome::FunctionValueCall(request) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::FunctionValueCall(request),
                );
            }
            DispatchOutcome::EvalRequest(request) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::EvalRequest(request),
                );
            }
            DispatchOutcome::Suspend(record) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::Suspended(record),
                );
            }
            DispatchOutcome::Fail(error) => {
                return finish_with_targeted_root_cleanup(
                    execution.heap,
                    &mut active_targeted_register_roots,
                    &mut active_targeted_frame_roots,
                    ExecutionCompletion::Failed(error),
                );
            }
            DispatchOutcome::Throw(value) => {
                execution.exceptions.throw(value);
                let pending = execution
                    .exceptions
                    .pending()
                    .unwrap_or(PendingException { value });
                let mut unwind =
                    ExceptionUnwindState::begin(pending, Some(frame.id), bytecode_index);
                if let Some(handler) = find_handler(code_block, bytecode_index) {
                    unwind.install_handler(handler);
                    execution.exceptions.replace_unwind(unwind);
                    pc = handler.target;
                } else {
                    execution.stack.unwind_through_frame(
                        execution.registers,
                        frame.id,
                        &mut unwind,
                    );
                    execution.exceptions.replace_unwind(unwind);
                    return finish_with_targeted_root_cleanup(
                        execution.heap,
                        &mut active_targeted_register_roots,
                        &mut active_targeted_frame_roots,
                        ExecutionCompletion::Threw(pending),
                    );
                }
            }
        }
    }
}

fn validate_baseline_fallback_request(
    stack: &mut ExecutionContextStack,
    code_block_id: CodeBlockId,
    cursor: InstructionCursor<'_>,
    request: BaselineFallbackRequest,
) -> Result<InstalledCallFrame, ExecutionError> {
    if request.code_block != code_block_id {
        return Err(ExecutionError::CodeBlockMismatch {
            expected: request.code_block,
            actual: Some(code_block_id),
        });
    }

    let (frame, _) = baseline_active_frame(stack, request.frame, request.code_block)?;
    if cursor
        .get(request.bytecode_index.offset() as usize)
        .is_none()
    {
        return Err(ExecutionError::InvalidBytecodeIndex(request.bytecode_index));
    }

    stack.mark_top_bytecode_index(request.bytecode_index);
    Ok(frame)
}

fn validate_single_dispatch_request(
    stack: &ExecutionContextStack,
    cursor: InstructionCursor<'_>,
    request: SingleDispatchRequest,
) -> Result<InstalledCallFrame, ExecutionError> {
    let (frame, _) = baseline_active_frame(stack, request.frame, request.code_block)?;
    if cursor
        .get(request.bytecode_index.offset() as usize)
        .is_none()
    {
        return Err(ExecutionError::InvalidBytecodeIndex(request.bytecode_index));
    }

    Ok(frame)
}

fn map_single_dispatch_outcome(
    state: SingleDispatchOutcomeState<'_>,
    context: SingleDispatchOutcomeContext<'_>,
    outcome: DispatchOutcome,
) -> SingleDispatchOutcome {
    let SingleDispatchOutcomeState {
        stack,
        registers,
        exceptions,
    } = state;
    let SingleDispatchOutcomeContext {
        frame,
        code_block,
        cursor,
        index,
        bytecode_index,
        call_handling,
    } = context;

    match outcome {
        DispatchOutcome::Continue => SingleDispatchOutcome::Continue(
            cursor
                .get(index.saturating_add(1))
                .map(|view| view.bytecode_index(index.saturating_add(1))),
        ),
        DispatchOutcome::ContinueTo(target) => {
            if target.is_some_and(|target| cursor.get(target.offset() as usize).is_none()) {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidBytecodeIndex(target.unwrap()))
            } else {
                SingleDispatchOutcome::Continue(target)
            }
        }
        DispatchOutcome::Jump(target) => {
            if cursor.get(target.offset() as usize).is_none() {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidBytecodeIndex(target))
            } else {
                SingleDispatchOutcome::Jump(target)
            }
        }
        DispatchOutcome::Return(value) => SingleDispatchOutcome::Return(value),
        DispatchOutcome::BaselineLoopHandoff(_) => {
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        }
        DispatchOutcome::OrdinaryBytecodeCall(request) => {
            if call_handling.ordinary_bytecode_call == OrdinaryBytecodeCallHandling::DeferToVm {
                SingleDispatchOutcome::OrdinaryBytecodeCall(request)
            } else {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidCallCompletion)
            }
        }
        DispatchOutcome::OrdinaryBytecodeConstruct(request) => {
            if call_handling.ordinary_bytecode_call == OrdinaryBytecodeCallHandling::DeferToVm {
                SingleDispatchOutcome::OrdinaryBytecodeConstruct(request)
            } else {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidCallCompletion)
            }
        }
        DispatchOutcome::FunctionValueCall(request) => {
            if call_handling.function_value_call == FunctionValueCallHandling::DeferToVm {
                SingleDispatchOutcome::FunctionValueCall(request)
            } else {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidCallCompletion)
            }
        }
        DispatchOutcome::EvalRequest(request) => {
            // Indirect eval defers to the Vm exactly like a function-value call;
            // it is only valid where the Vm owns re-entrancy.
            if call_handling.function_value_call == FunctionValueCallHandling::DeferToVm {
                SingleDispatchOutcome::EvalRequest(request)
            } else {
                SingleDispatchOutcome::Failed(ExecutionError::InvalidCallCompletion)
            }
        }
        DispatchOutcome::Suspend(record) => SingleDispatchOutcome::Suspended(record),
        DispatchOutcome::Fail(error) => SingleDispatchOutcome::Failed(error),
        DispatchOutcome::Throw(value) => {
            exceptions.throw(value);
            let pending = exceptions.pending().unwrap_or(PendingException { value });
            let mut unwind = ExceptionUnwindState::begin(pending, Some(frame), bytecode_index);
            if let Some(handler) = find_handler(code_block, bytecode_index) {
                unwind.install_handler(handler);
                exceptions.replace_unwind(unwind);
                SingleDispatchOutcome::Jump(handler.target)
            } else {
                stack.unwind_through_frame(registers, frame, &mut unwind);
                exceptions.replace_unwind(unwind);
                SingleDispatchOutcome::Threw(pending)
            }
        }
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct TargetedFrameRootPlan {
    records: Vec<TargetedRootRecord>,
    rootless_descriptors: Vec<FrameRootDescriptor>,
}

impl TargetedFrameRootPlan {
    fn resolve(
        heap: &Heap,
        snapshot: &ExecutionRootSnapshot,
    ) -> Result<TargetedFrameRootPlan, ExecutionError> {
        validate_root_records(
            snapshot
                .frame_roots
                .iter()
                .map(|descriptor| descriptor.root),
        )?;

        let mut records = Vec::new();
        let mut rootless_descriptors = Vec::new();
        for descriptor in &snapshot.frame_roots {
            if descriptor.root.heap != heap.id() {
                return Err(RootSetSemanticError::HeapMismatch {
                    expected: heap.id(),
                    actual: descriptor.root.heap,
                }
                .into());
            }

            let target = match descriptor.target {
                FrameRootTarget::Known(target) => target,
                FrameRootTarget::NoTarget | FrameRootTarget::Unknown => {
                    rootless_descriptors.push(*descriptor);
                    continue;
                }
            };

            records.push(TargetedRootRecord {
                root: descriptor.root,
                target,
            });
        }

        let set = TargetedRootSet::from_records(heap.id(), records)?;
        for record in set.records() {
            if !heap_has_allocation(heap, record.target) {
                return Err(HeapIntegrationError::UnknownCell(record.target).into());
            }
        }

        Ok(Self {
            records: set.records().to_vec(),
            rootless_descriptors,
        })
    }

    fn into_records(self) -> Vec<TargetedRootRecord> {
        self.records
    }
}

pub(crate) fn sync_targeted_frame_roots(
    owner_frame: CallFrameId,
    stack: &ExecutionContextStack,
    _registers: &RegisterFile,
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    let snapshot = stack.frame_root_snapshot_for_heap(heap, owner_frame)?;
    let targeted = TargetedFrameRootPlan::resolve(heap, &snapshot)?;
    sync_targeted_vm_roots(heap, active_roots, targeted.into_records())
}

pub(crate) fn sync_targeted_register_roots<H: DispatchHost>(
    owner_frame: CallFrameId,
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    heap: &mut Heap,
    host: &mut H,
    active_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    let snapshot = stack.register_root_snapshot_for_frame(heap, registers, owner_frame)?;
    let targeted = host.targeted_register_roots(heap, &snapshot)?;
    sync_targeted_vm_roots(heap, active_roots, targeted)
}

/// Allocation-free-per-instruction form of `sync_targeted_register_roots`.
///
/// Identical roots, identical register/retarget/unregister order; the only
/// difference is that every working collection is reused from `scratch` instead
/// of being freshly allocated each bytecode. The dispatch loops own one
/// `RegisterRootSyncScratch` across iterations and pass it in here per
/// instruction. See `RegisterRootSyncScratch` for why this exists (interpreter
/// hot-loop allocation churn) and that it has no C++ JSC counterpart.
pub(crate) fn sync_targeted_register_roots_buffered<H: DispatchHost>(
    owner_frame: CallFrameId,
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    heap: &mut Heap,
    host: &mut H,
    active_roots: &mut Vec<RootRecord>,
    scratch: &mut RegisterRootSyncScratch,
) -> Result<(), ExecutionError> {
    // 1. Fill the register-root snapshot into the reused buffer, then build a
    //    transient snapshot view that borrows it (no Vec allocation).
    stack.register_root_snapshot_for_frame_into(
        heap,
        registers,
        owner_frame,
        &mut scratch.snapshot_registers,
    )?;
    let snapshot = ExecutionRootSnapshot {
        frame_roots: Vec::new(),
        register_roots: std::mem::take(&mut scratch.snapshot_registers),
    };
    // 2. Resolve targeted records into the reused buffer.
    let targeted_result =
        host.targeted_register_roots_into(heap, &snapshot, &mut scratch.targeted_records);
    // Return the snapshot's register buffer to the scratch so its capacity is
    // reused next instruction, regardless of whether resolution succeeded.
    scratch.snapshot_registers = snapshot.register_roots;
    targeted_result?;

    sync_targeted_vm_roots_buffered(heap, active_roots, scratch)
}

pub(crate) fn sync_targeted_nonlocal_frame_roots(
    owner_frame: CallFrameId,
    stack: &ExecutionContextStack,
    _registers: &RegisterFile,
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    let snapshot = stack.nonlocal_frame_root_snapshot_for_heap(heap, owner_frame)?;
    let targeted = TargetedFrameRootPlan::resolve(heap, &snapshot)?;
    sync_targeted_vm_roots(heap, active_roots, targeted.into_records())
}

pub(crate) fn sync_targeted_nonlocal_register_roots<H: DispatchHost>(
    owner_frame: CallFrameId,
    stack: &ExecutionContextStack,
    registers: &RegisterFile,
    heap: &mut Heap,
    host: &mut H,
    active_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    let snapshot = stack.nonlocal_register_root_snapshot_for_frame(heap, registers, owner_frame)?;
    let targeted = host.targeted_register_roots(heap, &snapshot)?;
    sync_targeted_vm_roots(heap, active_roots, targeted)
}

fn sync_targeted_vm_roots(
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
    desired_records: Vec<TargetedRootRecord>,
) -> Result<(), ExecutionError> {
    let desired_records = desired_records
        .into_iter()
        .filter(|record| record.root.kind == RootKind::VMRegister)
        .collect::<Vec<_>>();
    let desired = TargetedRootSet::from_records(heap.id(), desired_records)?;
    let desired_root_ids = desired
        .records()
        .iter()
        .map(|record| record.root.id)
        .collect::<HashSet<_>>();
    let stale_roots = active_roots
        .iter()
        .copied()
        .filter(|root| !desired_root_ids.contains(&root.id))
        .collect::<Vec<_>>();

    apply_desired_vm_roots(heap, active_roots, &desired, &stale_roots)
}

/// Reusable scratch buffers for the per-instruction register-root sync.
///
/// The interpreter dispatch loop runs `sync_targeted_register_roots` after every
/// bytecode instruction. The straightforward version (`sync_targeted_vm_roots`)
/// allocates several fresh collections per instruction (the register snapshot
/// Vec, the host's targeted-record Vec, the filtered desired-record Vec, the
/// desired `TargetedRootSet`, the desired-id `HashSet`, and the stale-root Vec).
/// That allocation churn dominated the interpreter hot loop, so the dispatch
/// loops own one `RegisterRootSyncScratch` across iterations and clear-and-reuse
/// these buffers each instruction. This is a Rust-internal allocation-reuse
/// optimization with no C++ JSC counterpart; the produced roots and the order in
/// which they are registered/retargeted/unregistered are identical to the
/// allocating path.
#[derive(Default)]
pub(crate) struct RegisterRootSyncScratch {
    snapshot_registers: Vec<RegisterRootDescriptor>,
    targeted_records: Vec<TargetedRootRecord>,
    desired_set: TargetedRootSet,
    // `RootId`-keyed set using the in-tree integer hasher rather than std's
    // DoS-resistant SipHash. `RootId` is a VM-internal integer, so SipHash is
    // pure overhead on this per-bytecode buffer; only set membership is read,
    // so the swap is semantically inert.
    desired_root_ids: RootIdSet,
    stale_roots: Vec<RootRecord>,
}

impl RegisterRootSyncScratch {
    pub(crate) fn new() -> Self {
        Self::default()
    }
}

/// Buffered form of `sync_targeted_vm_roots`: filter `scratch.targeted_records`
/// to VMRegister roots and load them into the reused `scratch.desired_set`
/// (validating in place via `refill_from_records`), compute the stale set in the
/// reused `scratch.stale_roots`/`scratch.desired_root_ids` buffers, then apply
/// the same mutations as `sync_targeted_vm_roots`. No per-instruction
/// allocation.
fn sync_targeted_vm_roots_buffered(
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
    scratch: &mut RegisterRootSyncScratch,
) -> Result<(), ExecutionError> {
    let heap_id = heap.id();
    scratch.desired_set.refill_from_records(
        heap_id,
        scratch
            .targeted_records
            .iter()
            .copied()
            .filter(|record| record.root.kind == RootKind::VMRegister),
    )?;

    scratch.desired_root_ids.clear();
    scratch
        .desired_root_ids
        .extend(scratch.desired_set.records().iter().map(|r| r.root.id));

    scratch.stale_roots.clear();
    scratch.stale_roots.extend(
        active_roots
            .iter()
            .copied()
            .filter(|root| !scratch.desired_root_ids.contains(&root.id)),
    );

    apply_desired_vm_roots(
        heap,
        active_roots,
        &scratch.desired_set,
        &scratch.stale_roots,
    )
}

/// Shared core of the VM-register-root sync, used by both the allocating
/// (`sync_targeted_vm_roots`) and the buffered per-instruction
/// (`sync_targeted_register_roots_buffered`) entry points. `desired` is the
/// validated desired targeted-root set; `stale_roots` is the precomputed set of
/// currently-active roots that are absent from `desired`.
fn apply_desired_vm_roots(
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
    desired: &TargetedRootSet,
    stale_roots: &[RootRecord],
) -> Result<(), ExecutionError> {
    for root in stale_roots {
        let root = *root;
        // O(1) membership test by root identity instead of scanning the whole
        // live targeted-root set on every stale root (see TargetedRootSet index).
        if heap.targeted_roots().contains_root(root) {
            heap.unregister_targeted_root(root, RootSetMutationAuthority::VmRegisterFile)?;
        }
        active_roots.retain(|active| active.id != root.id);
    }

    for record in desired.records() {
        // O(1) lookup of the existing record by root identity instead of a linear
        // scan of the live targeted-root set per desired record.
        let existing = heap.targeted_roots().record_for_root(record.root).copied();
        match existing {
            Some(existing) if existing == *record => {
                if !active_roots
                    .iter()
                    .any(|active| active.id == record.root.id)
                {
                    active_roots.push(record.root);
                }
            }
            Some(_) => {
                heap.retarget_targeted_root(*record, RootSetMutationAuthority::VmRegisterFile)?;
                if !active_roots
                    .iter()
                    .any(|active| active.id == record.root.id)
                {
                    active_roots.push(record.root);
                }
            }
            None => {
                heap.register_targeted_root(*record, RootSetMutationAuthority::VmRegisterFile)?;
                if !active_roots
                    .iter()
                    .any(|active| active.id == record.root.id)
                {
                    active_roots.push(record.root);
                }
            }
        }
    }

    Ok(())
}

fn finish_with_targeted_root_cleanup(
    heap: &mut Heap,
    active_register_roots: &mut Vec<RootRecord>,
    active_frame_roots: &mut Vec<RootRecord>,
    completion: ExecutionCompletion,
) -> ExecutionCompletion {
    match cleanup_targeted_root_sets(heap, active_register_roots, active_frame_roots) {
        Ok(()) => completion,
        Err(error) => ExecutionCompletion::Failed(error),
    }
}

fn finish_single_dispatch_with_targeted_root_cleanup(
    heap: &mut Heap,
    active_register_roots: &mut Vec<RootRecord>,
    active_frame_roots: &mut Vec<RootRecord>,
    outcome: SingleDispatchOutcome,
) -> SingleDispatchOutcome {
    match cleanup_targeted_root_sets(heap, active_register_roots, active_frame_roots) {
        Ok(()) => outcome,
        Err(error) => SingleDispatchOutcome::Failed(error),
    }
}

pub(crate) fn cleanup_targeted_root_sets(
    heap: &mut Heap,
    active_register_roots: &mut Vec<RootRecord>,
    active_frame_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    let register_cleanup = cleanup_targeted_vm_roots(heap, active_register_roots);
    let frame_cleanup = cleanup_targeted_vm_roots(heap, active_frame_roots);
    register_cleanup.and(frame_cleanup)
}

fn cleanup_targeted_vm_roots(
    heap: &mut Heap,
    active_roots: &mut Vec<RootRecord>,
) -> Result<(), ExecutionError> {
    for root in std::mem::take(active_roots) {
        if heap
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.root == root)
        {
            heap.unregister_targeted_root(root, RootSetMutationAuthority::VmRegisterFile)?;
        }
    }
    Ok(())
}

fn heap_has_allocation(heap: &Heap, cell: CellId) -> bool {
    heap.allocation_records()
        .iter()
        .any(|record| record.response.cell == cell)
}

fn frame_root_target_for_cell(heap: &Heap, cell: CellId) -> FrameRootTarget {
    if heap_has_allocation(heap, cell) {
        FrameRootTarget::known(cell)
    } else {
        FrameRootTarget::unknown()
    }
}

pub(crate) fn find_handler(
    code_block: &CodeBlock,
    bytecode_index: BytecodeIndex,
) -> Option<UnwindHandler> {
    let offset = bytecode_index.offset();
    code_block
        .side_tables()
        .handlers
        .iter()
        .find_map(|handler| match (handler.range, handler.target) {
            (HandlerRange::Bytecode(range), HandlerTarget::Bytecode(target))
                if range.start.offset() <= offset && offset < range.end.offset() =>
            {
                Some(UnwindHandler { target })
            }
            _ => None,
        })
}

fn frame_root_id(frame: CallFrameId, source: FrameRootSource) -> RootId {
    RootId(
        FRAME_ROOT_ID_BASE
            .saturating_add(u64::from(frame.0).saturating_mul(16))
            .saturating_add(source.ordinal()),
    )
}

fn register_root_id(slot: usize) -> RootId {
    RootId(
        REGISTER_ROOT_ID_BASE
            .saturating_add(slot as u64)
            .saturating_add(1),
    )
}

fn value_cell_payload(value: RuntimeValue) -> Option<usize> {
    value.as_cell().map(|cell| cell.pointer_payload_bits())
}

fn validate_root_records(
    records: impl IntoIterator<Item = RootRecord>,
) -> Result<(), RootSetSemanticError> {
    crate::gc::RootSet::from_records(records.into_iter().collect()).map(|_| ())
}

