    fn assert_store_mutation_rejects_without_barrier(
        host: &mut CoreOpcodeDispatchHost,
        heap: &mut Heap,
        object: RuntimeValue,
        request: GeneratedPropertyStoreMutationRequest,
        reason: GeneratedPropertyStoreMutationMissReason,
    ) {
        let snapshot = object_store_mutation_snapshot(&host.objects, object);
        let barrier_count = heap.barrier_records().len();
        assert_eq!(
            store_mutation_miss_reason(host.commit_generated_property_store(heap, request)),
            reason
        );
        assert_eq!(heap.barrier_records().len(), barrier_count);
        assert_eq!(
            snapshot,
            object_store_mutation_snapshot(&host.objects, object)
        );
    }

    fn generated_guarded_property_load_plan(
        host: &mut CoreOpcodeDispatchHost,
        heap: &mut Heap,
        owner: CodeBlockId,
        base: RuntimeValue,
        key: &CorePropertyKey,
        offset: u32,
        request_key: u32,
    ) -> PropertyLoadGuardPlan {
        let (_outcome, record) = host
            .objects
            .get_property_with_lookup_record(base, key, property_lookup_site(offset))
            .expect("guarded property lookup record");
        host.record_property_lookup(record);
        let descriptor = host
            .drain_property_load_observation(
                heap,
                property_load_observation_request(owner, offset, request_key),
            )
            .expect("guarded property observation drain")
            .expect("guarded property observation");
        plan_property_load_guard_plan_from_observation(&descriptor)
            .expect("guarded property plan derivation")
            .expect("guarded property plan")
    }

