    #[test]
    fn generated_store_transition_commit_fires_old_structure_watchpoint_event() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let object = host.allocate_null_prototype_object_for_test();
        let old_structure = object_structure_id(&host.objects, object);
        let new_structure = host.objects.allocate_structure_id();
        let planned_offset = PropertyOffset::new(
            host.objects
                .find(object)
                .expect("object")
                .next_property_offset,
        );
        let plan = generated_property_store_transition_plan(
            old_structure,
            planned_offset,
            new_structure,
            11,
        );
        let request = structure_watchpoint_request(13, old_structure);
        host.start_structure_transition_watchpoints(&[request])
            .expect("structure watchpoint start");

        let commit = store_mutation_commit(host.commit_generated_property_store(
            &mut heap,
            generated_property_store_mutation_request(&plan, object, RuntimeValue::from_i32(42)),
        ));

        assert_eq!(commit.base_structure_before, old_structure);
        assert_eq!(commit.base_structure_after, new_structure);
        assert_eq!(commit.planned_new_structure, Some(new_structure));
        let events = host.drain_watchpoint_fire_events();
        assert_eq!(events.len(), 1);
        assert_structure_watchpoint_event(
            events[0],
            request.set,
            old_structure,
            WatchpointGeneration(1),
        );
        assert_eq!(
            host.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent { old_structure }]
        );
        assert_eq!(object_structure_id(&host.objects, object), new_structure);
    }

    #[test]
    fn structure_chain_invalidation_events_track_shape_and_prototype_transitions() {
        let mut objects = CoreObjectStore::default();
        let object = objects.allocate_with_prototype(None);
        let first = CorePropertyKey::String("first".into());
        let second = CorePropertyKey::String("second".into());

        let initial_structure = object_structure_id(&objects, object);
        objects
            .set_data_own(object, &first, RuntimeValue::from_i32(1))
            .unwrap();
        assert_eq!(
            objects.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent {
                old_structure: initial_structure
            }]
        );
        let after_first = object_structure_id(&objects, object);

        objects
            .set_data_own(object, &first, RuntimeValue::from_i32(2))
            .unwrap();
        assert_eq!(object_structure_id(&objects, object), after_first);
        assert!(objects
            .drain_structure_chain_invalidation_events()
            .is_empty());

        objects
            .define_data_property(
                object,
                &first,
                RuntimeValue::from_i32(3),
                CorePropertyAttributes {
                    writable: false,
                    enumerable: true,
                    configurable: true,
                },
            )
            .unwrap();
        assert_eq!(
            objects.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent {
                old_structure: after_first
            }]
        );
        let after_attribute_change = object_structure_id(&objects, object);

        objects
            .put_data_own(object, &second, RuntimeValue::from_i32(4))
            .unwrap();
        assert_eq!(
            objects.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent {
                old_structure: after_attribute_change
            }]
        );
        let after_second = object_structure_id(&objects, object);

        assert_eq!(objects.delete_property(object, &second), Ok(true));
        assert_eq!(
            objects.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent {
                old_structure: after_second
            }]
        );
        let after_delete = object_structure_id(&objects, object);

        let prototype = objects.allocate_with_prototype(None);
        objects
            .set_prototype_or_null(object, Some(prototype))
            .unwrap();
        assert_eq!(
            objects.drain_structure_chain_invalidation_events(),
            vec![StructureChainInvalidationEvent {
                old_structure: after_delete
            }]
        );
        let after_prototype = object_structure_id(&objects, object);

        objects
            .set_prototype_or_null(object, Some(prototype))
            .unwrap();
        assert_eq!(object_structure_id(&objects, object), after_prototype);
        assert!(objects
            .drain_structure_chain_invalidation_events()
            .is_empty());
    }

    #[test]
    fn property_lookup_records_own_data_facts() {
        let mut objects = CoreObjectStore::default();
        let object = objects.allocate_with_prototype(None);
        let key = CorePropertyKey::String("field".into());
        let value = RuntimeValue::from_i32(9);
        objects.set_data_own(object, &key, value).unwrap();

        let (outcome, record) = objects
            .get_property_with_lookup_record(object, &key, property_lookup_site(7))
            .unwrap();

        assert_eq!(outcome, CorePropertyGet::Data(value));
        assert_eq!(record.bytecode_index, Some(BytecodeIndex::from_offset(7)));
        assert_eq!(record.opcode, Some(CoreOpcode::GetByName));
        assert_eq!(record.base, object);
        assert_eq!(record.base_object, Some(object));
        assert_eq!(
            record.base_structure,
            Some(object_structure_id(&objects, object))
        );
        assert_eq!(record.key, key);
        assert_eq!(record.holder, Some(object));
        assert_eq!(record.offset, Some(PropertyOffset::new(0)));
        assert_eq!(record.prototype_depth, 0);
        assert_eq!(
            record.classification,
            CorePropertyLookupClassification::OwnData
        );
        assert!(!record.may_call_js);
        assert_eq!(record.cacheability, PropertyCacheability::Allowed);
        assert_eq!(record.returned_value, Some(value));
        assert_eq!(record.getter, None);
        assert_eq!(record.access_case_kind, Some(AccessCaseKind::Load));
        assert_eq!(
            record.chain,
            vec![CorePropertyLookupChainEntry {
                object,
                structure: object_structure_id(&objects, object),
            }]
        );
    }

    #[test]
    fn property_lookup_records_numeric_string_boundaries() {
        let mut objects = CoreObjectStore::default();
        let object = objects.allocate_with_prototype(None);
        let canonical = CorePropertyKey::String("0".into());
        let canonical_value = RuntimeValue::from_i32(10);
        objects
            .set_data_own(object, &canonical, canonical_value)
            .unwrap();

        let (outcome, record) = objects
            .get_property_with_lookup_record(object, &canonical, property_lookup_site(8))
            .unwrap();

        assert_eq!(outcome, CorePropertyGet::Data(canonical_value));
        assert_eq!(object_property_offset(&objects, object, &canonical), None);
        assert_eq!(record.offset, None);
        assert_eq!(
            record.classification,
            CorePropertyLookupClassification::OwnData
        );
        assert_eq!(record.access_case_kind, Some(AccessCaseKind::Load));

        for (name, value, expected_offset, site) in [
            ("00", RuntimeValue::from_i32(11), PropertyOffset::new(0), 9),
            ("01", RuntimeValue::from_i32(12), PropertyOffset::new(1), 10),
        ] {
            let key = CorePropertyKey::String(name.into());
            objects.set_data_own(object, &key, value).unwrap();

            let (outcome, record) = objects
                .get_property_with_lookup_record(object, &key, property_lookup_site(site))
                .unwrap();

            assert_eq!(outcome, CorePropertyGet::Data(value));
            assert_eq!(
                object_property_offset(&objects, object, &key),
                Some(expected_offset)
            );
            assert_eq!(record.offset, Some(expected_offset));
            assert_eq!(record.access_case_kind, Some(AccessCaseKind::Load));
            assert_eq!(record.cacheability, PropertyCacheability::Allowed);
        }
        assert_eq!(object_property_offset(&objects, object, &canonical), None);
    }

