    #[test]
    fn property_lookup_failed_recording_drops_stale_record_and_pending_site() {
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::String("field".into());
        let value = RuntimeValue::from_i32(42);
        host.objects.set_data_own(object, &key, value).unwrap();
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        let block = code_block(Vec::new());

        {
            let mut state = dispatch_state(
                &mut stack,
                &mut registers,
                &mut exceptions,
                &mut heap,
                &block,
            );
            host.begin_property_lookup_recording(property_lookup_site(31));
            let result = host.get_property_value(&mut state, object, &key, object);
            assert_eq!(result, Ok(value));
        }
        assert_eq!(
            host.last_property_lookup_record()
                .expect("successful lookup record")
                .returned_value,
            Some(value)
        );
        assert_eq!(host.pending_property_lookup_site, None);

        host.begin_property_lookup_recording(property_lookup_site(37));
        assert_eq!(host.last_property_lookup_record(), None);
        {
            let mut state = dispatch_state(
                &mut stack,
                &mut registers,
                &mut exceptions,
                &mut heap,
                &block,
            );
            // C++ JSC: accessing a property on a primitive number routes through
            // Number.prototype (autoboxing). "field" is not on Number.prototype,
            // so the result is undefined rather than an error.
            let result =
                host.get_property_value(&mut state, RuntimeValue::from_i32(1), &key, object);
            assert_eq!(result, Ok(RuntimeValue::undefined()));
        }
        // With number autoboxing, the lookup through Number.prototype records
        // an opaque record, so the record is present (not None).
        assert!(host.last_property_lookup_record().is_some());
        assert_eq!(host.pending_property_lookup_site, None);
    }

    #[test]
    fn property_lookup_observation_drain_binds_unbound_own_data_base_and_holder() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(77));
        let object = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        host.objects
            .set_data_own(object, &key, RuntimeValue::from_i32(9))
            .unwrap();
        let (_outcome, record) = host
            .objects
            .get_property_with_lookup_record(object, &key, property_lookup_site(7))
            .unwrap();
        let expected_structure = record.base_structure;
        let expected_offset = record.offset;
        assert_ne!(expected_structure, Some(StructureId::INVALID));
        assert_eq!(expected_offset, Some(PropertyOffset::new(0)));
        assert_eq!(heap.cell_for_payload(cell_payload(object)), None);
        host.record_property_lookup(record);

        let descriptor = host
            .drain_property_load_observation(
                &mut heap,
                property_load_observation_request(owner, 7, 11),
            )
            .unwrap()
            .expect("property load observation");

        let object_cell = heap_cell_for_value(&heap, object);
        assert_eq!(descriptor.base_object, Some(ObjectId(object_cell)));
        assert_eq!(descriptor.holder_object, Some(ObjectId(object_cell)));
        assert_eq!(
            descriptor.key,
            CacheKey::Property(PropertyKey::from_identifier(Identifier::from_atom(
                AtomId::from_table_slot(11),
            )))
        );
        assert_eq!(descriptor.base_structure, expected_structure);
        assert_eq!(descriptor.offset, Some(PropertyOffset::new(0)));
        assert_eq!(descriptor.prototype_depth, 0);
        assert_eq!(
            descriptor.chain,
            vec![PropertyLoadObservationChainEntry {
                object: ObjectId(object_cell),
                structure: expected_structure.unwrap(),
                next_prototype: None,
            }]
        );
        assert_eq!(
            descriptor.observed_access_case_kind,
            Some(AccessCaseKind::Load)
        );
        assert_eq!(descriptor.cacheability, PropertyCacheability::Allowed);
        assert_eq!(
            descriptor.readiness,
            PropertyLoadObservationReadiness::ReadyForAttachment
        );
        assert!(!descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingBaseStructureGuard));
        assert!(!descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingOffset));
        assert_eq!(descriptor.validate(), Ok(()));
        assert_eq!(host.last_property_lookup_record(), None);
    }

