    #[test]
    fn generated_property_load_megamorphic_holder_probe_misses_for_stale_holder_metadata() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let holder = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        host.objects.bind_object_to_heap(&mut heap, holder).unwrap();
        host.objects
            .set_data_own(holder, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let request =
            generated_property_load_megamorphic_holder_probe_request(&host.objects, holder, 11);

        let mut default_holder = request;
        default_holder.holder = ObjectId::default();
        assert_eq!(
            probe_miss_reason(
                host.probe_generated_property_load_megamorphic_holder(default_holder)
            ),
            GeneratedPropertyLoadProbeMissReason::UnknownObject
        );

        let mut missing_key = request;
        missing_key.key = cache_key_for_identifier(12);
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load_megamorphic_holder(missing_key)),
            GeneratedPropertyLoadProbeMissReason::MissingProperty
        );

        let mut mismatched_offset = request;
        mismatched_offset.offset = PropertyOffset::new(request.offset.raw() + 1);
        assert_eq!(
            probe_miss_reason(
                host.probe_generated_property_load_megamorphic_holder(mismatched_offset)
            ),
            GeneratedPropertyLoadProbeMissReason::KeyOffsetMismatch
        );

        let accessor = host.objects.allocate_with_prototype(None);
        let getter = host.objects.allocate_function(0, Vec::new(), None);
        host.objects
            .define_accessor(accessor, &key, Some(getter), None)
            .unwrap();
        host.objects
            .bind_object_to_heap(&mut heap, accessor)
            .unwrap();
        let accessor_request = GeneratedPropertyLoadMegamorphicHolderProbeRequest {
            key: cache_key_for_identifier(11),
            base_structure: StructureId::new(1),
            holder: ObjectId(
                host.objects
                    .find(accessor)
                    .expect("accessor object")
                    .cell_id,
            ),
            offset: PropertyOffset::new(0),
        };
        assert_eq!(
            probe_miss_reason(
                host.probe_generated_property_load_megamorphic_holder(accessor_request)
            ),
            GeneratedPropertyLoadProbeMissReason::NonDataProperty
        );

        let target = host.objects.allocate_with_prototype(None);
        let handler = host.objects.allocate_with_prototype(None);
        let proxy = host
            .objects
            .allocate_proxy_with_write_barrier(&mut heap, target, handler)
            .unwrap();
        host.objects.bind_object_to_heap(&mut heap, proxy).unwrap();
        let proxy_id = ObjectId(host.objects.find(proxy).expect("proxy object").cell_id);
        let mut proxy_request = request;
        proxy_request.holder = proxy_id;
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load_megamorphic_holder(proxy_request)),
            GeneratedPropertyLoadProbeMissReason::OpaqueObject
        );
    }

    #[test]
    fn generated_property_load_probe_misses_for_unsupported_or_stale_cases() {
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.objects.allocate_with_prototype(None);
        let key = CorePropertyKey::Identifier(11);
        host.objects
            .set_data_own(object, &key, RuntimeValue::from_i32(42))
            .unwrap();
        let structure = object_structure_id(&host.objects, object);
        let offset = object_property_offset(&host.objects, object, &key).expect("offset");
        let plan = generated_property_load_plan(structure, offset, 11);

        let mut mismatched_structure = plan.clone();
        mismatched_structure.access_case.base_structure =
            Some(StructureId::new(structure.raw().saturating_add(1)));
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&mismatched_structure, object)
            )),
            GeneratedPropertyLoadProbeMissReason::StructureMismatch
        );

        let mut mismatched_offset = plan.clone();
        mismatched_offset.access_case.offset = Some(PropertyOffset::new(offset.raw() + 1));
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&mismatched_offset, object)
            )),
            GeneratedPropertyLoadProbeMissReason::KeyOffsetMismatch
        );

        let missing = host.objects.allocate_with_prototype(None);
        let missing_plan = generated_property_load_plan(
            object_structure_id(&host.objects, missing),
            PropertyOffset::new(0),
            11,
        );
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&missing_plan, missing)
            )),
            GeneratedPropertyLoadProbeMissReason::MissingProperty
        );

        let accessor = host.objects.allocate_with_prototype(None);
        let getter = host.objects.allocate_function(0, Vec::new(), None);
        host.objects
            .define_accessor(accessor, &key, Some(getter), None)
            .unwrap();
        let accessor_plan = generated_property_load_plan(
            object_structure_id(&host.objects, accessor),
            PropertyOffset::new(0),
            11,
        );
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&accessor_plan, accessor)
            )),
            GeneratedPropertyLoadProbeMissReason::NonDataProperty
        );

        let prototype = host.objects.allocate_with_prototype(None);
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let child = host.objects.allocate_with_prototype(Some(prototype));
        let prototype_plan = generated_property_load_plan(
            object_structure_id(&host.objects, child),
            PropertyOffset::new(0),
            11,
        );
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&prototype_plan, child)
            )),
            GeneratedPropertyLoadProbeMissReason::MissingProperty
        );

        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&plan, RuntimeValue::from_i32(1))
            )),
            GeneratedPropertyLoadProbeMissReason::NonCellBase
        );

        let mut dynamic_key = plan.clone();
        dynamic_key.key = CacheKey::Dynamic;
        dynamic_key.access_case.key = CacheKey::Dynamic;
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&dynamic_key, object)
            )),
            GeneratedPropertyLoadProbeMissReason::KeyNotRepresentable
        );

        let indexed_key = CacheKey::Property(PropertyKey::from_index(
            PropertyIndex::from_canonical_index(0),
        ));
        let mut nonrepresentable_key = plan.clone();
        nonrepresentable_key.key = indexed_key;
        nonrepresentable_key.access_case.key = indexed_key;
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&nonrepresentable_key, object)
            )),
            GeneratedPropertyLoadProbeMissReason::KeyNotRepresentable
        );

        let mut unsupported_metadata = plan.clone();
        unsupported_metadata.effect_contract = PropertyLoadAccessCasePlanContract {
            effects: PropertyLoadAccessCaseEffects::Unsupported,
            rooting: PropertyLoadAccessCaseRooting::Unsupported,
        };
        assert_eq!(
            probe_miss_reason(host.probe_generated_property_load(
                generated_property_load_probe_request(&unsupported_metadata, object)
            )),
            GeneratedPropertyLoadProbeMissReason::UnsupportedPlanMetadata
        );
    }

