    #[test]
    fn generated_guarded_property_load_probe_misses_for_guard_failures() {
        let key = CorePropertyKey::Identifier(11);

        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(123));
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 51, 11);
        host.objects
            .set_data_own(
                object,
                &CorePropertyKey::Identifier(12),
                RuntimeValue::from_i32(1),
            )
            .unwrap();
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardStructureMismatch
        );

        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 53, 11);
        let new_prototype = host.objects.allocate_with_prototype(None);
        host.objects
            .set_prototype_or_null(object, Some(new_prototype))
            .unwrap();
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardPrototypeLinkMismatch
        );

        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let mut plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 55, 11);
        host.objects
            .set_data_own(object, &key, RuntimeValue::from_i32(99))
            .unwrap();
        let base_structure = object_structure_id(&host.objects, object);
        plan.descriptor.base_structure = base_structure;
        plan.descriptor.chain.entries[0].structure = base_structure;
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardNoOwnPropertyProofFailed
        );

        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let mut plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 57, 11);
        let getter = host.objects.allocate_function(0, Vec::new(), None);
        host.objects
            .define_accessor(prototype, &key, Some(getter), None)
            .unwrap();
        let holder_index = plan.descriptor.chain.entries.len() - 1;
        plan.descriptor.chain.entries[holder_index].structure =
            object_structure_id(&host.objects, prototype);
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::GuardDataPropertyProofFailed
        );

        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let plan =
            generated_guarded_property_load_plan(&mut host, &mut heap, owner, object, &key, 59, 11);
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&plan, RuntimeValue::from_i32(1))
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::NonCellBase
        );

        let mut dynamic_key = plan.clone();
        dynamic_key.descriptor.key = CacheKey::Dynamic;
        assert_eq!(
            guarded_probe_miss_reason(host.probe_generated_guarded_property_load(
                generated_guarded_property_load_probe_request(&dynamic_key, object)
            )),
            GeneratedGuardedPropertyLoadProbeMissReason::KeyNotRepresentable
        );
    }

    #[test]
    fn property_lookup_observation_drain_binds_prototype_holder() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(78));
        let prototype = host.objects.allocate_with_prototype(None);
        let object = host.objects.allocate_with_prototype(Some(prototype));
        let key = CorePropertyKey::Identifier(11);
        host.objects
            .set_data_own(prototype, &key, RuntimeValue::from_i32(31))
            .unwrap();
        let (_outcome, record) = host
            .objects
            .get_property_with_lookup_record(object, &key, property_lookup_site(11))
            .unwrap();
        host.record_property_lookup(record);

        let descriptor = host
            .drain_property_load_observation(
                &mut heap,
                property_load_observation_request(owner, 11, 11),
            )
            .unwrap()
            .expect("prototype property load observation");

        let object_cell = heap_cell_for_value(&heap, object);
        let prototype_cell = heap_cell_for_value(&heap, prototype);
        assert_eq!(descriptor.base_object, Some(ObjectId(object_cell)));
        assert_eq!(descriptor.holder_object, Some(ObjectId(prototype_cell)));
        assert_eq!(
            descriptor.base_structure,
            Some(object_structure_id(&host.objects, object))
        );
        assert_eq!(descriptor.offset, Some(PropertyOffset::new(0)));
        assert_eq!(descriptor.prototype_depth, 1);
        assert_eq!(
            descriptor.chain,
            vec![
                PropertyLoadObservationChainEntry {
                    object: ObjectId(object_cell),
                    structure: object_structure_id(&host.objects, object),
                    next_prototype: Some(ObjectId(prototype_cell)),
                },
                PropertyLoadObservationChainEntry {
                    object: ObjectId(prototype_cell),
                    structure: object_structure_id(&host.objects, prototype),
                    next_prototype: None,
                },
            ]
        );
        assert_eq!(
            descriptor.observed_access_case_kind,
            Some(AccessCaseKind::Load)
        );
        assert!(descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::PrototypeChainGuardRequired));
        assert!(!descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingBaseStructureGuard));
        assert!(!descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingOffset));
        assert_eq!(descriptor.validate(), Ok(()));
        assert_eq!(host.last_property_lookup_record(), None);
    }

