    #[test]
    fn property_lookup_observation_indexed_mutations_preserve_structure_ids() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();

        let array = host.objects.allocate_array();
        let array_structure = object_structure_id(&host.objects, array);
        host.objects
            .put_index(&mut heap, array, 0, RuntimeValue::from_i32(1))
            .unwrap();
        assert_eq!(object_structure_id(&host.objects, array), array_structure);
        assert_eq!(host.objects.delete_index(array, 0), Ok(true));
        assert_eq!(object_structure_id(&host.objects, array), array_structure);
        host.objects
            .put_index(&mut heap, array, 0, RuntimeValue::from_i32(2))
            .unwrap();
        assert_eq!(
            host.objects
                .delete_property(array, &CorePropertyKey::String("0".into())),
            Ok(true)
        );
        assert_eq!(object_structure_id(&host.objects, array), array_structure);

        let buffer = host.objects.allocate_array_buffer(1);
        let typed_array = host
            .objects
            .allocate_uint8_array_with_write_barrier(&mut heap, buffer, 0, 1)
            .unwrap();
        let typed_array_structure = object_structure_id(&host.objects, typed_array);
        assert_eq!(
            host.objects.write_typed_element(typed_array, 0, 255.0),
            Ok(true)
        );
        assert_eq!(
            object_structure_id(&host.objects, typed_array),
            typed_array_structure
        );
        host.objects
            .put_index(&mut heap, typed_array, 0, RuntimeValue::from_i32(17))
            .unwrap();
        assert_eq!(
            object_structure_id(&host.objects, typed_array),
            typed_array_structure
        );
    }

    #[test]
    fn property_lookup_observation_drain_records_proxy_as_opaque() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(83));
        let target = host.objects.allocate_with_prototype(None);
        let handler = host.objects.allocate_with_prototype(None);
        let proxy = host
            .objects
            .allocate_proxy_with_write_barrier(&mut heap, target, handler)
            .unwrap();
        let key = CorePropertyKey::Identifier(11);
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let block = code_block(Vec::new());

        {
            let mut state = dispatch_state(
                &mut stack,
                &mut registers,
                &mut exceptions,
                &mut heap,
                &block,
            );
            host.begin_property_lookup_recording(property_lookup_site(25));
            let result = host.get_property_value(&mut state, proxy, &key, proxy);
            assert_eq!(result, Ok(RuntimeValue::undefined()));
        }

        let descriptor = host
            .drain_property_load_observation(
                &mut heap,
                property_load_observation_request(owner, 25, 11),
            )
            .unwrap()
            .expect("proxy property load observation");

        assert_eq!(descriptor.observed_access_case_kind, None);
        assert_eq!(
            descriptor.cacheability,
            PropertyCacheability::TaintedByOpaqueObject
        );
        assert_eq!(descriptor.base_structure, None);
        assert_eq!(descriptor.offset, None);
        assert!(descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::OpaqueResult));
        assert_eq!(descriptor.validate(), Ok(()));
    }

    #[test]
    fn property_lookup_observation_drain_rejects_mismatched_key_and_keeps_opaque_blocked() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let owner = CodeBlockId(CellId(80));
        let key = CorePropertyKey::Identifier(12);
        host.record_property_lookup(CorePropertyLookupRecord::opaque(
            property_lookup_site(17),
            RuntimeValue::from_i32(1),
            None,
            &key,
            true,
            PropertyCacheability::TaintedByOpaqueObject,
        ));

        assert_eq!(
            host.drain_property_load_observation(
                &mut heap,
                property_load_observation_request(owner, 17, 11),
            )
            .unwrap(),
            None
        );
        assert_eq!(host.last_property_lookup_record(), None);

        let key = CorePropertyKey::Identifier(11);
        host.record_property_lookup(CorePropertyLookupRecord::opaque(
            property_lookup_site(19),
            RuntimeValue::from_i32(1),
            None,
            &key,
            true,
            PropertyCacheability::TaintedByOpaqueObject,
        ));
        let descriptor = host
            .drain_property_load_observation(
                &mut heap,
                property_load_observation_request(owner, 19, 11),
            )
            .unwrap()
            .expect("opaque property load observation");

        assert_eq!(descriptor.base_object, None);
        assert_eq!(descriptor.holder_object, None);
        assert_eq!(descriptor.observed_access_case_kind, None);
        assert_eq!(
            descriptor.cacheability,
            PropertyCacheability::TaintedByOpaqueObject
        );
        assert!(descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::OpaqueResult));
        assert_eq!(descriptor.validate(), Ok(()));
    }

    fn allocate_test_code_block_id(heap: &mut Heap) -> CodeBlockId {
        let metadata = static_cell_metadata_registry()
            .metadata_for_type(CellType::CodeBlock)
            .map(|descriptor| descriptor.metadata)
            .expect("code block metadata");
        let allocation = heap
            .allocate_record(HeapAllocationRequest {
                heap: heap.id(),
                subspace: "auxiliary",
                metadata,
                byte_size: std::mem::size_of::<CodeBlock>().max(1),
                mode: AllocationMode::Normal,
                may_trigger_collection: false,
            })
            .expect("code block allocation");
        heap.publish_cell(allocation.cell)
            .expect("code block publication");
        CodeBlockId(allocation.cell)
    }

    #[derive(Default)]
    struct TargetedRootObservingHost {
        dispatch_roots: Vec<Vec<TargetedRootRecord>>,
    }

    impl DispatchHost for TargetedRootObservingHost {
        fn dispatch_instruction(
            &mut self,
            state: &mut DispatchState<'_>,
            _instruction: DispatchInstruction<'_>,
        ) -> DispatchOutcome {
            self.dispatch_roots
                .push(state.heap.targeted_roots().records().to_vec());
            DispatchOutcome::Return(RuntimeValue::undefined())
        }
    }

    fn assert_single_value_store_barrier(
        heap: &Heap,
        owner: CellId,
        target: Option<CellId>,
        outcome: BarrierRequirementOutcome,
    ) {
        assert_eq!(heap.barrier_records().len(), 1);
        assert_value_store_barrier_record(&heap.barrier_records()[0], owner, target, outcome);
    }

    fn assert_value_store_barrier_at(
        heap: &Heap,
        index: usize,
        owner: CellId,
        target: Option<CellId>,
        outcome: BarrierRequirementOutcome,
    ) {
        assert_value_store_barrier_record(&heap.barrier_records()[index], owner, target, outcome);
    }

    fn assert_value_store_barrier_record(
        record: &crate::gc::WriteBarrierApplicationRecord,
        owner: CellId,
        target: Option<CellId>,
        outcome: BarrierRequirementOutcome,
    ) {
        assert_eq!(record.request.owner, owner);
        assert_eq!(record.request.target, target);
        assert_eq!(
            record.request.context,
            BarrierWriteContext::store(
                BarrierFieldKind::Value,
                CellState::PossiblyBlack,
                target.map(|_| CellState::PossiblyGrey),
            )
        );
        assert_eq!(
            record.request.authority,
            BarrierMutationAuthority::MutatorFieldWrite
        );
        assert!(record.request.owner_is_published);
        assert_eq!(record.outcome, outcome);
    }

    fn single_register_snapshot(heap: &Heap, value: RuntimeValue) -> ExecutionRootSnapshot {
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        stack.enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
            code_block: CodeBlockId(CellId(11)),
            global_object: GlobalObjectId(ObjectId(CellId(12))),
            this_value: RuntimeValue::undefined(),
        }));
        stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: None,
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 0,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![value],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();
        stack
            .root_snapshot(heap.id(), &registers)
            .expect("valid roots")
    }

    fn dispatch_state<'a>(
        stack: &'a mut ExecutionContextStack,
        registers: &'a mut RegisterFile,
        exceptions: &'a mut ExceptionState,
        heap: &'a mut Heap,
        code_block: &'a CodeBlock,
    ) -> DispatchState<'a> {
        DispatchState {
            stack,
            registers,
            exceptions,
            heap,
            code_block,
            ordinary_bytecode_call_handling: OrdinaryBytecodeCallHandling::DirectInterpreter,
            function_value_call_handling: FunctionValueCallHandling::DirectInterpreter,
        }
    }

