    #[test]
    fn production_put_closure_cell_opcode_records_required_value_barrier() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        let cell_register = VirtualRegister::local(0);
        let value_register = VirtualRegister::local(1);
        let block = code_block_with_frame(
            Vec::new(),
            RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 2,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            },
        );
        let code_block_id = CodeBlockId(CellId(41));
        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let frame = stack.top_frame().expect("frame").id;
        let window = stack.top_frame().expect("frame").register_window;
        let cell = host
            .objects
            .allocate_closure_cell(RuntimeValue::undefined());
        let target = host.objects.allocate();
        registers.write(window, cell_register, cell).unwrap();
        registers.write(window, value_register, target).unwrap();
        let instruction = core_typed(
            0,
            CoreOpcode::PutClosureCell,
            vec![
                Operand::Register(cell_register),
                Operand::Register(value_register),
            ],
        );
        let start = heap.barrier_records().len();

        let outcome = {
            let mut state = dispatch_state(
                &mut stack,
                &mut registers,
                &mut exceptions,
                &mut heap,
                &block,
            );
            host.dispatch_instruction(
                &mut state,
                DispatchInstruction {
                    frame,
                    code_block: code_block_id,
                    bytecode_index: BytecodeIndex::from_offset(0),
                    next_bytecode_index: None,
                    opcode: instruction.opcode,
                    operands: &instruction.operands,
                },
            )
        };

        let owner_cell = host.objects.cell_id(cell).expect("closure cell");
        let target_cell = host.objects.cell_id(target).expect("target cell");
        assert_eq!(outcome, DispatchOutcome::Continue);
        assert_eq!(host.objects.get_closure_cell(cell).unwrap(), target);
        assert_eq!(heap.barrier_records().len(), start + 1);
        assert_value_store_barrier_at(
            &heap,
            start,
            owner_cell,
            Some(target_cell),
            BarrierRequirementOutcome::Required(BarrierAction::MarkingBarrier),
        );
    }

