    #[test]
    fn single_dispatch_cleans_targeted_roots_on_return_fail_and_throw() {
        struct FixedTargetRootHost {
            target: CellId,
            outcome: DispatchOutcome,
            dispatch_roots: Vec<Vec<TargetedRootRecord>>,
        }

        impl DispatchHost for FixedTargetRootHost {
            fn targeted_register_roots(
                &mut self,
                _heap: &mut Heap,
                snapshot: &ExecutionRootSnapshot,
            ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
                let root = snapshot.register_roots.first().expect("register root").root;
                Ok(vec![TargetedRootRecord {
                    root,
                    target: self.target,
                }])
            }

            fn dispatch_instruction(
                &mut self,
                state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.dispatch_roots
                    .push(state.heap.targeted_roots().records().to_vec());
                self.outcome.clone()
            }
        }

        let cases = vec![
            (
                DispatchOutcome::Return(RuntimeValue::from_i32(7)),
                SingleDispatchOutcome::Return(RuntimeValue::from_i32(7)),
                None,
            ),
            (
                DispatchOutcome::Fail(ExecutionError::ExpectedObject),
                SingleDispatchOutcome::Failed(ExecutionError::ExpectedObject),
                None,
            ),
            (
                DispatchOutcome::Throw(RuntimeValue::from_i32(13)),
                SingleDispatchOutcome::Threw(PendingException {
                    value: RuntimeValue::from_i32(13),
                }),
                Some(PendingException {
                    value: RuntimeValue::from_i32(13),
                }),
            ),
        ];

        for (dispatch_outcome, expected_outcome, expected_pending) in cases {
            let block = code_block(vec![typed(0)]);
            let mut stack = ExecutionContextStack::default();
            let mut registers = RegisterFile::default();
            let mut exceptions = ExceptionState::default();
            let mut heap = Heap::new();
            let code_block_id = allocate_test_code_block_id(&mut heap);
            enter_program_frame(
                &mut stack,
                &mut registers,
                code_block_id,
                &block,
                Vec::new(),
            );
            let frame = stack.top_frame().unwrap().id;
            let mut host = FixedTargetRootHost {
                target: code_block_id.0,
                outcome: dispatch_outcome,
                dispatch_roots: Vec::new(),
            };

            let outcome = execute_single_dispatch(
                InterpreterExecutionState {
                    stack: &mut stack,
                    registers: &mut registers,
                    exceptions: &mut exceptions,
                    heap: &mut heap,
                },
                SingleDispatchRequest::new(code_block_id, frame, BytecodeIndex::from_offset(0)),
                &block,
                &mut host,
            );

            assert_eq!(outcome, expected_outcome);
            assert_eq!(exceptions.pending(), expected_pending);
            assert_eq!(host.dispatch_roots.len(), 1);
            assert!(host.dispatch_roots[0]
                .iter()
                .any(|record| record.target == code_block_id.0));
            assert!(heap.targeted_roots().records().is_empty());
        }
    }

    #[test]
    fn single_dispatch_rejects_invalid_frame_code_block_and_index() {
        struct RejectingHost;
        impl DispatchHost for RejectingHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                DispatchOutcome::Fail(ExecutionError::BaselineGeneratedExecutionRejected)
            }
        }

        let block = code_block(vec![typed(0)]);
        let code_block_id = CodeBlockId(CellId(103));
        let wrong_code_block = CodeBlockId(CellId(104));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let frame = stack.top_frame().unwrap().id;
        let mut host = RejectingHost;

        let wrong_frame = execute_single_dispatch(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            SingleDispatchRequest::new(
                code_block_id,
                CallFrameId(frame.0 + 1),
                BytecodeIndex::from_offset(0),
            ),
            &block,
            &mut host,
        );

        assert_eq!(
            wrong_frame,
            SingleDispatchOutcome::Failed(ExecutionError::FrameMismatch {
                expected: CallFrameId(frame.0 + 1),
                actual: Some(frame),
            })
        );

        let code_block_mismatch = execute_single_dispatch(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            SingleDispatchRequest::new(wrong_code_block, frame, BytecodeIndex::from_offset(0)),
            &block,
            &mut host,
        );

        assert_eq!(
            code_block_mismatch,
            SingleDispatchOutcome::Failed(ExecutionError::CodeBlockMismatch {
                expected: wrong_code_block,
                actual: Some(code_block_id),
            })
        );

        let invalid_index = execute_single_dispatch(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            SingleDispatchRequest::new(code_block_id, frame, BytecodeIndex::from_offset(1)),
            &block,
            &mut host,
        );

        assert_eq!(
            invalid_index,
            SingleDispatchOutcome::Failed(ExecutionError::InvalidBytecodeIndex(
                BytecodeIndex::from_offset(1)
            ))
        );
        assert!(heap.targeted_roots().records().is_empty());
    }

