    #[test]
    fn targeted_register_roots_sync_alongside_known_frame_roots() {
        let register = VirtualRegister::local(0);
        let mirror = VirtualRegister::local(1);
        // NewObject installs a cell root for local0, then Move copies that cell
        // into local1. The Move is a genuine cell-membership change (it sets the
        // register-root dirty signal), so the sync after it runs with local0's
        // register root already in `existing` -- exercising steady-state
        // register/frame root coexistence without depending on a redundant
        // recompute after a non-mutating op (the per-op tax this gating removes;
        // see the dispatch-loop gate comment).
        let block = code_block(vec![
            core_typed(0, CoreOpcode::NewObject, vec![Operand::Register(register)]),
            core_typed(
                1,
                CoreOpcode::Move,
                vec![Operand::Register(mirror), Operand::Register(register)],
            ),
            core_typed(2, CoreOpcode::Return, vec![Operand::Register(register)]),
        ]);
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        let code_block_id = allocate_test_code_block_id(&mut heap);
        let heap_id = heap.id();
        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            Vec::new(),
        );
        let frame = stack.top_frame().unwrap().id;
        let frame_root = TargetedRootRecord {
            root: RootRecord {
                id: frame_root_id(frame, FrameRootSource::CodeBlock),
                kind: RootKind::VMRegister,
                heap: heap_id,
            },
            target: code_block_id.0,
        };
        let mut host = ObservingCoreHost::new();

        let result = execute_code_block(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            code_block_id,
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        let value = if let ExecutionCompletion::Returned(value) = result {
            value
        } else {
            unreachable!("expected returned object, got {result:?}");
        };
        let returned_cell = heap_cell_for_value(&heap, value);
        assert!(host.observations.iter().any(|observation| {
            observation.existing.contains(&frame_root)
                && observation.desired.iter().any(|record| {
                    record.root.id == register_root_id(0) && record.target == returned_cell
                })
        }));
        assert!(host.observations.iter().any(|observation| {
            observation.existing.contains(&frame_root)
                && observation.existing.iter().any(|record| {
                    record.root.id == register_root_id(0) && record.target == returned_cell
                })
        }));
        assert!(heap.targeted_roots().records().is_empty());
    }

    #[test]
    fn generic_dispatch_host_default_hook_does_not_register_targeted_roots() {
        struct DefaultHookHost {
            count: usize,
        }

        impl DispatchHost for DefaultHookHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.count = self.count.saturating_add(1);
                DispatchOutcome::Return(RuntimeValue::undefined())
            }
        }

        let block = code_block(vec![typed(0)]);
        let code_block_id = CodeBlockId(CellId(34));
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let mut exceptions = ExceptionState::default();
        let mut heap = Heap::new();
        let cell_value = RuntimeValue::from_encoded(EncodedJsValue((0x5678 << 8) | 0x20));
        let payload = cell_payload(cell_value);
        enter_program_frame(
            &mut stack,
            &mut registers,
            code_block_id,
            &block,
            vec![cell_value],
        );
        let mut host = DefaultHookHost { count: 0 };

        let result = execute_code_block(
            InterpreterExecutionState {
                stack: &mut stack,
                registers: &mut registers,
                exceptions: &mut exceptions,
                heap: &mut heap,
            },
            code_block_id,
            &block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(
            result,
            ExecutionCompletion::Returned(RuntimeValue::undefined())
        );
        assert_eq!(host.count, 1);
        assert_eq!(heap.cell_for_payload(payload), None);
        assert!(heap.targeted_roots().records().is_empty());
    }

    #[test]
    fn execution_root_snapshot_describes_frame_and_register_roots() {
        let mut stack = ExecutionContextStack::default();
        let mut registers = RegisterFile::default();
        let heap = Heap::new();
        let heap_id = heap.id();
        let code_block_id = CodeBlockId(CellId(21));
        stack.enter(ExecutionEntryRecord::Function(FunctionExecutionEntry {
            code_block: code_block_id,
            function: ObjectId(CellId(22)),
            this_value: RuntimeValue::undefined(),
            context: Some(ObjectId(CellId(23))),
            argument_count: 1,
            specialization: CodeSpecializationKind::Call,
        }));
        stack
            .push_frame(
                &mut registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: Some(ObjectId(CellId(22))),
                    callee_value: None,
                    lexical_scope: Some(ScopeId(5)),
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 1,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::from_i32(7)],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let snapshot = stack
            .root_snapshot_for_heap(&heap, &registers)
            .expect("valid roots");

        assert_eq!(snapshot.frame_roots.len(), 3);
        assert_eq!(snapshot.register_roots.len(), 2);
        assert_eq!(
            snapshot
                .frame_roots
                .iter()
                .map(|descriptor| descriptor.target)
                .collect::<Vec<_>>(),
            vec![
                FrameRootTarget::Unknown,
                FrameRootTarget::Unknown,
                FrameRootTarget::NoTarget
            ]
        );
        assert!(snapshot
            .precise_root_records()
            .iter()
            .all(|root| root.kind == RootKind::VMRegister && root.heap == heap_id));
    }

    #[test]
    fn targeted_register_roots_bind_unbound_object_root() {
        let mut host = CoreOpcodeDispatchHost::new();
        let mut heap = Heap::new();
        let object = host.objects.allocate();
        let payload = cell_payload(object);
        let snapshot = single_register_snapshot(&heap, object);

        assert_eq!(heap.cell_for_payload(payload), None);

        let targeted = host
            .targeted_register_roots(&mut heap, &snapshot)
            .expect("targeted roots");

        assert_eq!(targeted.len(), 1);
        assert_eq!(targeted[0].root, snapshot.register_roots[0].root);
        assert_ne!(targeted[0].target, CellId::default());
        assert_eq!(heap.cell_for_payload(payload), Some(targeted[0].target));
        assert_eq!(heap.payload_for_cell(targeted[0].target), Some(payload));
        assert_eq!(host.objects.cell_id(object), Some(targeted[0].target));
        assert!(heap.targeted_roots().records().is_empty());
    }

